function n(r){return r==null?"—":`₹${(r/100).toFixed(2)} Cr`}function e(r){return r==null?"—":r>=100?n(r):`₹${r.toFixed(1)}L`}function u(r){return r==null?"—":`₹${Number(r).toLocaleString("en-IN")}`}function f(r){return r?new Date(r).toLocaleDateString("en-IN",{month:"short",year:"numeric"}):"—"}function i(r){return r==null?"—":`${Math.round(r).toLocaleString("en-IN")} sqft`}function o(r){return r==null?"—":`${r} wk${r!==1?"s":""}`}function a(r){return r>=7?"var(--red)":r>=4?"var(--amber)":"var(--green)"}function c(r){return r>=7?"CRITICAL":r>=5.5?"HIGH":r>=4?"MEDIUM":"LOW"}function s(r){return r>=7?"rgba(239,68,68,0.12)":r>=4?"rgba(245,158,11,0.10)":"rgba(34,197,94,0.10)"}function g(r){const t=["#3B82F6","#8B5CF6","#00C896","#F59E0B","#EF4444"];return t[r%t.length]}export{i as a,a as b,u as c,f as d,o as e,e as f,c as g,g as h,s as i};
